/**
 * Emits an index.ts barrel file that re-exports all generated modules.
 */

import type { HydratedNodeModel } from '../node-model.ts';

export interface EmitIndexConfig {
	grammar: string;
	nodes: HydratedNodeModel[];
}

export function emitIndex(config: EmitIndexConfig): string {
	const lines: string[] = [
		'// Auto-generated by @sittir/codegen — do not edit',
		'',
		'// Types (grammar + construction types + navigation types + enums)',
		"export * from './types.js';",
		'',
		'// Factories (ir namespace with .from())',
		"export { ir } from './ir.js';",
		'',
		'// Shared resolution utilities',
		"export * from './utils.js';",
		'',
		'// Tree node hydration and in-place editing',
		"export { readNode, edit } from './wrap.js';",
		'',
		'// .from() resolution (tree-shakeable, separate from factories)',
		"export * from './from.js';",
		'',
		'// Constants (node kinds, keywords, operators)',
		"export * from './consts.js';",
		'',
		'// Core re-exports',
		"export { createRenderer } from '@sittir/core';",
		"export type { NodeData, TreeNode } from './types.js';",
		"export type { Edit, CSTNode, RenderContext } from '@sittir/types';",
		'',
	];

	return lines.join('\n');
}
